="fa fa-folder"></i></div>									<input type="text" class="form-control" id="po_no" name="po_no"										value="<?php if (isset($detil)) echo ($detil[0]['po_no']); ?>" placeholder="No PO">								</div>								<p></p>								<div class="well">									<dl class="dl">										<dt>Total Jenis Part</dt>										<dd id="total-jenis">0</dd>										<dt>Total Part</dt>										<dd id="total-part">0</dd>									</dl>								</div>																<div class="well">									<button class="btn btn-primary" type="submit"><i class="fa fa-hdd-o"></i> Simpan Data</button>								</div>							</div>						</div>					</form>				</div>			</div>